function createRenderer() {
  function clamp(value) { return Math.max(0, Math.min(1, value)); }
  function easeOut(value) { value = clamp(value); return 1 - Math.pow(1 - value, 3); }
  function easeInOut(value) { value = clamp(value); return value < 0.5 ? 4 * value * value * value : 1 - Math.pow(-2 * value + 2, 3) / 2; }
  function pulse(t, speed, phase) { return 0.5 + 0.5 * Math.sin(t * speed + phase); }
  function roundedRect(ctx, x, y, width, height, radius) {
    ctx.beginPath();
    ctx.moveTo(x + radius, y);
    ctx.lineTo(x + width - radius, y);
    ctx.quadraticCurveTo(x + width, y, x + width, y + radius);
    ctx.lineTo(x + width, y + height - radius);
    ctx.quadraticCurveTo(x + width, y + height, x + width - radius, y + height);
    ctx.lineTo(x + radius, y + height);
    ctx.quadraticCurveTo(x, y + height, x, y + height - radius);
    ctx.lineTo(x, y + radius);
    ctx.quadraticCurveTo(x, y, x + radius, y);
    ctx.closePath();
  }
  function render(time, context) {
    var ctx = context.mainContext;
    var width = context.width;
    var height = context.height;
    var intro = easeOut(time / 1.2);
    var cards = easeOut((time - 1.0) / 1.5);
    var pipeline = easeOut((time - 2.8) / 1.6);
    var final = easeOut((time - 5.8) / 1.1);
    drawBackdrop(ctx, width, height, time);
    drawDepthGrid(ctx, width, height, time, intro);
    drawHeroCopy(ctx, width, height, time, intro, final);
    drawCommandDeck(ctx, width, height, time, cards);
    drawFloatingCards(ctx, width, height, time, cards);
    drawPipeline(ctx, width, height, time, pipeline);
    drawFinalLockup(ctx, width, height, time, final);
    drawProgress(ctx, width, height, time, 8);
  }
  function drawBackdrop(ctx, width, height, time) {
    var gradient = ctx.createLinearGradient(0, 0, width, height);
    gradient.addColorStop(0, '#030712');
    gradient.addColorStop(0.34, '#07172A');
    gradient.addColorStop(0.68, '#15102A');
    gradient.addColorStop(1, '#101809');
    ctx.fillStyle = gradient;
    ctx.fillRect(0, 0, width, height);
    ctx.save();
    ctx.globalCompositeOperation = 'screen';
    ctx.globalAlpha = 0.24;
    var cyan = ctx.createRadialGradient(width * 0.22, height * 0.18, 40, width * 0.22, height * 0.18, 600);
    cyan.addColorStop(0, '#00D4FF');
    cyan.addColorStop(1, 'rgba(0,212,255,0)');
    ctx.fillStyle = cyan;
    ctx.fillRect(0, 0, width, height);
    var amber = ctx.createRadialGradient(width * 0.82, height * 0.72, 40, width * 0.82, height * 0.72, 660);
    amber.addColorStop(0, '#F2AA4C');
    amber.addColorStop(1, 'rgba(242,170,76,0)');
    ctx.fillStyle = amber;
    ctx.fillRect(0, 0, width, height);
    var green = ctx.createRadialGradient(width * 0.57, height * 0.28, 20, width * 0.57, height * 0.28, 520);
    green.addColorStop(0, '#7BD88F');
    green.addColorStop(1, 'rgba(123,216,143,0)');
    ctx.fillStyle = green;
    ctx.fillRect(0, 0, width, height);
    ctx.restore();
    ctx.save();
    ctx.globalAlpha = 0.4;
    for (var i = 0; i < 90; i++) {
      var x = (i * 173 + Math.sin(time * 0.34 + i) * 34) % width;
      var y = (i * 97 + Math.cos(time * 0.27 + i * 0.4) * 28) % height;
      ctx.fillStyle = i % 3 === 0 ? '#00D4FF' : i % 3 === 1 ? '#7BD88F' : '#F2AA4C';
      ctx.globalAlpha = 0.08 + (i % 5) * 0.035;
      ctx.beginPath();
      ctx.arc(x, y, 1.2 + (i % 4), 0, Math.PI * 2);
      ctx.fill();
    }
    ctx.restore();
  }
  function drawDepthGrid(ctx, width, height, time, amount) {
    ctx.save();
    ctx.translate(width / 2, height * 0.68);
    ctx.rotate(-0.08);
    ctx.globalAlpha = 0.13 * amount;
    ctx.strokeStyle = '#AEEBFF';
    ctx.lineWidth = 1;
    var spacing = 64;
    var offset = (time * 28) % spacing;
    for (var x = -width; x <= width; x += spacing) {
      ctx.beginPath();
      ctx.moveTo(x + offset, -height);
      ctx.lineTo(x - 360 + offset, height);
      ctx.stroke();
    }
    for (var y = -height; y <= height; y += spacing) {
      ctx.beginPath();
      ctx.moveTo(-width, y + offset);
      ctx.lineTo(width, y + offset);
      ctx.stroke();
    }
    ctx.restore();
  }
  function drawHeroCopy(ctx, width, height, time, intro, final) {
    var slide = (1 - intro) * -80;
    ctx.save();
    ctx.translate(slide, 0);
    ctx.globalAlpha = intro * (1 - final * 0.36);
    ctx.textAlign = 'left';
    ctx.fillStyle = '#FFFFFF';
    ctx.font = '900 96px Arial, sans-serif';
    ctx.fillText('Ship AI videos', 118, 178);
    ctx.fillText('from JSON.', 118, 286);
    var shimmer = ctx.createLinearGradient(118 + time * 180 % 620, 0, 620 + time * 180 % 620, 0);
    shimmer.addColorStop(0, '#00D4FF');
    shimmer.addColorStop(0.5, '#FFFFFF');
    shimmer.addColorStop(1, '#F2AA4C');
    ctx.fillStyle = shimmer;
    ctx.font = '900 31px Arial, sans-serif';
    ctx.fillText('Design motion once. Render every launch.', 124, 360);
    ctx.fillStyle = '#B8C7D9';
    ctx.font = '26px Arial, sans-serif';
    ctx.fillText('Puppeteer + Canvas + WebCodecs + deterministic timelines', 124, 407);
    drawPill(ctx, 124, 462, 'AI prompt ? JSON', '#00D4FF', intro);
    drawPill(ctx, 354, 462, 'Preview in browser', '#7BD88F', intro);
    drawPill(ctx, 610, 462, 'Export MP4', '#F2AA4C', intro);
    ctx.restore();
  }
  function drawPill(ctx, x, y, label, color, alpha) {
    ctx.save();
    ctx.globalAlpha = alpha;
    ctx.fillStyle = 'rgba(255,255,255,0.08)';
    roundedRect(ctx, x, y, 190, 48, 24);
    ctx.fill();
    ctx.strokeStyle = color;
    ctx.lineWidth = 1.5;
    ctx.stroke();
    ctx.fillStyle = '#EEF7FF';
    ctx.font = '800 17px Arial, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText(label, x + 95, y + 31);
    ctx.restore();
  }
  function drawCommandDeck(ctx, width, height, time, amount) {
    var x = 1060 + (1 - amount) * 180;
    var y = 132;
    ctx.save();
    ctx.globalAlpha = amount;
    ctx.translate(x, y);
    ctx.rotate((-5 + Math.sin(time * 0.8) * 1.2) * Math.PI / 180);
    ctx.shadowColor = 'rgba(0,0,0,0.55)';
    ctx.shadowBlur = 60;
    ctx.shadowOffsetY = 30;
    var shell = ctx.createLinearGradient(0, 0, 620, 700);
    shell.addColorStop(0, 'rgba(255,255,255,0.22)');
    shell.addColorStop(1, 'rgba(255,255,255,0.06)');
    ctx.fillStyle = shell;
    roundedRect(ctx, 0, 0, 620, 700, 42);
    ctx.fill();
    ctx.shadowBlur = 0;
    ctx.strokeStyle = 'rgba(255,255,255,0.22)';
    ctx.lineWidth = 1;
    ctx.stroke();
    ctx.fillStyle = 'rgba(3,7,18,0.62)';
    roundedRect(ctx, 36, 38, 548, 128, 24);
    ctx.fill();
    ctx.fillStyle = '#8DEBFF';
    ctx.font = '800 20px monospace';
    ctx.fillText('$ ui2v render hero-ai-launch.json', 66, 90);
    ctx.fillStyle = '#7BD88F';
    ctx.fillText('? encoded 240 frames ? hero.mp4', 66, 126);
    drawMiniTimeline(ctx, time, 54, 214, 512, amount);
    drawCodePreview(ctx, time, 54, 310);
    drawMiniPlayer(ctx, time, 342, 314);
    ctx.restore();
  }
  function drawMiniTimeline(ctx, time, x, y, width, amount) {
    ctx.fillStyle = 'rgba(255,255,255,0.08)';
    roundedRect(ctx, x, y, width, 56, 16);
    ctx.fill();
    var labels = ['prompt', 'layout', 'motion', 'encode'];
    for (var i = 0; i < labels.length; i++) {
      var segmentX = x + 18 + i * 122;
      ctx.fillStyle = i === 0 ? '#00D4FF' : i === 1 ? '#7BD88F' : i === 2 ? '#F2AA4C' : '#A78BFA';
      roundedRect(ctx, segmentX, y + 15, 96 * amount, 26, 13);
      ctx.fill();
      ctx.fillStyle = '#07111F';
      ctx.font = '800 13px Arial, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText(labels[i], segmentX + 48, y + 33);
    }
    ctx.fillStyle = '#FFFFFF';
    ctx.beginPath();
    ctx.arc(x + 22 + ((time / 8) % 1) * (width - 44), y + 28, 7, 0, Math.PI * 2);
    ctx.fill();
  }
  function drawCodePreview(ctx, time, x, y) {
    ctx.fillStyle = 'rgba(0,0,0,0.26)';
    roundedRect(ctx, x, y, 248, 300, 22);
    ctx.fill();
    var lines = ['{', '  "duration": 8,', '  "fps": 30,', '  "scene": "hero",', '  "style": "cinematic",', '  "cta": "Ship now"', '}'];
    ctx.font = '17px monospace';
    for (var i = 0; i < lines.length; i++) {
      ctx.fillStyle = i % 2 ? '#BDEFFF' : '#F6FBFF';
      ctx.globalAlpha = 0.58 + pulse(time, 2, i) * 0.3;
      ctx.fillText(lines[i], x + 24, y + 42 + i * 34);
    }
    ctx.globalAlpha = 1;
  }
  function drawMiniPlayer(ctx, time, x, y) {
    ctx.fillStyle = 'rgba(255,255,255,0.1)';
    roundedRect(ctx, x, y, 222, 300, 22);
    ctx.fill();
    var preview = ctx.createLinearGradient(x, y, x + 222, y + 300);
    preview.addColorStop(0, '#07172A');
    preview.addColorStop(0.48, '#123A5A');
    preview.addColorStop(1, '#33210C');
    ctx.fillStyle = preview;
    roundedRect(ctx, x + 18, y + 20, 186, 220, 18);
    ctx.fill();
    ctx.save();
    ctx.beginPath();
    roundedRect(ctx, x + 18, y + 20, 186, 220, 18);
    ctx.clip();
    for (var i = 0; i < 18; i++) {
      ctx.strokeStyle = i % 3 === 0 ? '#00D4FF' : '#F2AA4C';
      ctx.globalAlpha = 0.16;
      ctx.beginPath();
      ctx.arc(x + 111, y + 130, 20 + i * 10 + time * 8 % 10, 0, Math.PI * 2);
      ctx.stroke();
    }
    ctx.restore();
    ctx.globalAlpha = 1;
    ctx.fillStyle = '#FFFFFF';
    ctx.font = '900 24px Arial, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('MP4', x + 111, y + 279);
  }
  function drawFloatingCards(ctx, width, height, time, amount) {
    var cards = [
      ['Launch trailer', '8s hero video', '#00D4FF', 150, 602],
      ['Data story', 'live metrics', '#7BD88F', 430, 675],
      ['Brand system', 'repeatable code', '#F2AA4C', 704, 598]
    ];
    for (var i = 0; i < cards.length; i++) {
      var card = cards[i];
      var rise = (1 - amount) * 60;
      var bob = Math.sin(time * 1.3 + i) * 8;
      ctx.save();
      ctx.globalAlpha = amount;
      ctx.translate(card[3], card[4] + rise + bob);
      ctx.rotate((-3 + i * 2 + Math.sin(time + i) * 0.8) * Math.PI / 180);
      ctx.fillStyle = 'rgba(255,255,255,0.09)';
      roundedRect(ctx, 0, 0, 230, 118, 24);
      ctx.fill();
      ctx.strokeStyle = card[2];
      ctx.lineWidth = 1.5;
      ctx.stroke();
      ctx.fillStyle = card[2];
      ctx.beginPath();
      ctx.arc(34, 36, 11 + pulse(time, 4, i) * 3, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = '#FFFFFF';
      ctx.font = '900 24px Arial, sans-serif';
      ctx.fillText(card[0], 58, 44);
      ctx.fillStyle = '#B8C7D9';
      ctx.font = '19px Arial, sans-serif';
      ctx.fillText(card[1], 30, 82);
      ctx.restore();
    }
  }
  function drawPipeline(ctx, width, height, time, amount) {
    var y = 886;
    var labels = ['prompt', 'JSON', 'Canvas', 'WebCodecs', 'MP4'];
    ctx.save();
    ctx.globalAlpha = amount;
    ctx.textAlign = 'center';
    for (var i = 0; i < labels.length; i++) {
      var x = 420 + i * 260;
      ctx.fillStyle = 'rgba(3,7,18,0.58)';
      roundedRect(ctx, x - 86, y - 50, 172, 100, 22);
      ctx.fill();
      ctx.strokeStyle = i === 4 ? '#F2AA4C' : '#00D4FF';
      ctx.lineWidth = 1.5;
      ctx.stroke();
      ctx.fillStyle = '#FFFFFF';
      ctx.font = '900 24px Arial, sans-serif';
      ctx.fillText(labels[i], x, y + 8);
      if (i < labels.length - 1) {
        var nextX = x + 130;
        ctx.strokeStyle = 'rgba(255,255,255,0.28)';
        ctx.beginPath();
        ctx.moveTo(nextX - 30, y);
        ctx.lineTo(nextX + 70, y);
        ctx.stroke();
        ctx.fillStyle = '#7BD88F';
        ctx.beginPath();
        ctx.arc(nextX - 28 + ((time * 80 + i * 40) % 100), y, 5, 0, Math.PI * 2);
        ctx.fill();
      }
    }
    ctx.restore();
  }
  function drawFinalLockup(ctx, width, height, time, amount) {
    ctx.save();
    ctx.globalAlpha = amount;
    ctx.fillStyle = 'rgba(3,7,18,' + (0.38 * amount) + ')';
    ctx.fillRect(0, 0, width, height);
    ctx.textAlign = 'center';
    var glow = ctx.createRadialGradient(width / 2, height / 2, 20, width / 2, height / 2, 420);
    glow.addColorStop(0, 'rgba(0,212,255,0.36)');
    glow.addColorStop(1, 'rgba(0,212,255,0)');
    ctx.fillStyle = glow;
    ctx.fillRect(0, 0, width, height);
    ctx.fillStyle = '#FFFFFF';
    ctx.font = '900 92px Arial, sans-serif';
    ctx.fillText('ui2v', width / 2, 430);
    ctx.fillStyle = '#BDEFFF';
    ctx.font = '30px Arial, sans-serif';
    ctx.fillText('Generated video that looks good in your README.', width / 2, 488);
    ctx.fillStyle = '#F2AA4C';
    roundedRect(ctx, width / 2 - 178, 548, 356, 76, 24);
    ctx.fill();
    ctx.fillStyle = '#07111F';
    ctx.font = '900 24px Arial, sans-serif';
    ctx.fillText('npm install -g ui2v', width / 2, 596);
    ctx.restore();
  }
  function drawProgress(ctx, width, height, time, duration) {
    ctx.save();
    ctx.fillStyle = 'rgba(255,255,255,0.14)';
    roundedRect(ctx, 120, height - 72, width - 240, 12, 6);
    ctx.fill();
    var gradient = ctx.createLinearGradient(120, 0, width - 120, 0);
    gradient.addColorStop(0, '#00D4FF');
    gradient.addColorStop(0.55, '#7BD88F');
    gradient.addColorStop(1, '#F2AA4C');
    ctx.fillStyle = gradient;
    roundedRect(ctx, 120, height - 72, (width - 240) * clamp(time / duration), 12, 6);
    ctx.fill();
    ctx.restore();
  }
  return { render: render };
}
